solution_code:
#include <iostream>

template <typename T>
class MinMax {
    T m_min;
    T m_max;
public:
    MinMax(T first) : m_min{ first }, m_max{ first } {}

    void update(T val) {
        if (val < m_min) m_min = val;
        if (val > m_max) m_max = val;
    }

    T getMin() const { return m_min; }
    T getMax() const { return m_max; }
};

int main() {
    int n;
    std::cin >> n;

    int first;
    std::cin >> first;
    MinMax<int> mm{ first };

    for (int i = 1; i < n; ++i) {
        int val;
        std::cin >> val;
        mm.update(val);
    }

    std::cout << "Min: " << mm.getMin() << "\n";
    std::cout << "Max: " << mm.getMax() << "\n";
    return 0;
}

