#include <iostream>

template <typename T>
class Pair {
    T m_first;
    T m_second;
public:
    Pair(T first, T second) : m_first{ first }, m_second{ second } {}
    T first()  const { return m_first; }
    T second() const { return m_second; }

    void printSwapped() const {
        std::cout << m_second << " " << m_first << "\n";
    }
};

int main() {
    int a, b;
    std::cin >> a >> b;
    Pair<int> p{ a, b };
    p.printSwapped();
    return 0;
}
